import { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

export default function DriverCompletedTasks() {
  const [tasks, setTasks] = useState([]);

const getCompletedTasks = async () => {
  try {
    const res = await axios.get(Api.get_All_Emg_Req);

    console.log("Completed Tasks Response:", res.data);

    setTasks(res.data.data);
  } catch (error) {
    console.log(error);
  }
};

  useEffect(() => {
    getCompletedTasks();
  }, []);

return (
  <div className="min-h-screen bg-[#4CBB17]/20 p-8">
    <h1 className="text-4xl font-bold text-green-900 mb-8 text-center">
      Completed Tasks
    </h1>

    {tasks.length === 0 ? (
      <div className="bg-white p-8 rounded-xl shadow text-center">
        No Completed Tasks Found
      </div>
    ) : (
      <div className="grid md:grid-cols-3 gap-4">
        {tasks.map((task) => (
          <div
            key={task._id}
            className="bg-white border rounded-2xl p-5 hover:shadow-lg transition"
          >
            <p className="text-xs text-gray-500">
              REQUEST #{task._id.slice(-4)}
            </p>

            <h3 className="text-xl font-semibold text-green-800 mt-1">
              📍 {task.location?.location}
            </h3>

            <div className="flex justify-between items-center mt-4">
              <span className="font-medium">
                Priority: {task.priority}
              </span>

              
            </div>

            <p className="text-sm text-gray-500 mt-4">
              Created:{" "}
              {task.createdAt &&
                new Date(task.createdAt).toLocaleString("en-IN", {
                  day: "2-digit",
                  month: "short",
                  year: "numeric",
                  hour: "2-digit",
                  minute: "2-digit",
                  hour12: true,
                })}
            </p>

            {task.scheduledDate && (
              <p className="text-sm text-sky-700 mt-2 font-medium">
                Scheduled:{" "}
                {new Date(task.scheduledDate).toLocaleDateString(
                  "en-IN",
                  {
                    day: "2-digit",
                    month: "short",
                    year: "numeric",
                  }
                )}
                {" | "}
                {task.scheduledTime}
              </p>
            )}

            {task.arrivedAt && (
              <p className="text-sm text-orange-700 mt-2 font-medium">
                Arrived:{" "}
                {new Date(task.arrivedAt).toLocaleString("en-IN", {
                  day: "2-digit",
                  month: "short",
                  year: "numeric",
                  hour: "2-digit",
                  minute: "2-digit",
                  hour12: true,
                })}
              </p>
            )}

            {task.completedAt && (
              <p className="text-sm text-green-700 mt-2 font-medium">
                Completed:{" "}
                {new Date(task.completedAt).toLocaleString("en-IN", {
                  day: "2-digit",
                  month: "short",
                  year: "numeric",
                  hour: "2-digit",
                  minute: "2-digit",
                  hour12: true,
                })}
              </p>
            )}
          </div>
        ))}
      </div>
    )}
  </div>
);
}
